INSERT INTO public.lessons (id,course_id,title,content_type,url,file_path,article_content,estimated_minutes,sort_order) VALUES
  ('a3d10900-0000-4000-8000-000000000000','a3d00000-0000-4000-8000-000000000000','確認テスト ─ 企業価値評価','quiz',NULL,NULL,NULL,3,2),
  ('a3d20900-0000-4000-8000-000000000000','a3d00000-0000-4000-8000-000000000000','確認テスト ─ 資本政策','quiz',NULL,NULL,NULL,3,4),
  ('a3d30900-0000-4000-8000-000000000000','a3d00000-0000-4000-8000-000000000000','確認テスト ─ M&Aの財務','quiz',NULL,NULL,NULL,3,6),
  ('a3d40900-0000-4000-8000-000000000000','a3d00000-0000-4000-8000-000000000000','確認テスト ─ 経営者のための管理会計','quiz',NULL,NULL,NULL,3,8)
INSERT INTO public.quiz_questions (lesson_id,question,option_a,option_b,option_c,option_d,correct_option,sort_order) VALUES
('a3d10900-0000-4000-8000-000000000000','本文が示す企業価値評価の本質は、どれか。','一つの会社の値段を、複数の角度から見積もり、妥当な幅を見定める作業','決算書を隅々まで読み、書かれている正しい値段を探し当てる作業','純資産の額を計算し、それをそのまま会社の値段とする作業','最も高く出た数字を採用し、交渉の要求額を決める作業','A',0),
('a3d10900-0000-4000-8000-000000000000','本文で、DCF・類似会社比較・純資産方式が「見ているもの」の対応として正しいのは、どれか。','DCFは相場、類似会社比較は過去、純資産方式は未来を見ている','DCFは未来、類似会社比較は現在(市場)、純資産方式は過去を見ている','DCFは過去、類似会社比較は未来、純資産方式は現在を見ている','三つとも同じく未来の稼ぐ力だけを見ている','B',1),
('a3d10900-0000-4000-8000-000000000000','本文が挙げる「失敗②:DCFのきれいさにだまされる」への修正は、どれか。','計算結果ではなく、その手前にある前提を一つずつ疑う','より多くの桁まで、計算をさらに精緻にやり直す','純資産方式の数字だけを最終的な値段として採用する','相場の倍率をそのままあてはめて数字を確定させる','A',2),
('a3d20900-0000-4000-8000-000000000000','本文が示す資本政策の本質は、どれか。','お金をどう集め、どう還すかを、会社の局面に合わせて設計すること','目の前の現金が足りるか足りないかを、その都度回すこと','どんな会社にも当てはまる、理想の資本構成を一つ当てること','自己資本比率を常に100%に近づけ、借入をゼロにすること','A',0),
('a3d20900-0000-4000-8000-000000000000','本文で、資本政策の三つのレバーと「失うもの」の対応として正しいのは、どれか。','借入は持ち分、増資は自由、配当は返済を失う','借入は自由(返済と利息)、増資は持ち分、配当は社内の体力を失う','三つとも何も失わず、タダでお金が手に入る','借入は体力、増資は返済、配当は持ち分を失う','B',1),
('a3d20900-0000-4000-8000-000000000000','本文が挙げる「失敗①:借りやすいから借りすぎる」への修正は、どれか。','金利が低いうちに、投資のたびにできるだけ多く借りておく','借りる金額ではなく毎年の返済額を見て、利益が2割減った年でも耐えられるかで判断する','借入をやめ、必要な資金はすべて増資だけで賄う','稼いだ利益をすべて内部留保にため込み、投資を控える','B',2),
('a3d30900-0000-4000-8000-000000000000','本文が示すM&Aの財務の本質は、どれか。','払う額に対して、受け取る価値が見合うかを見極める作業','相手が出してきた言い値が正しいかどうかを確かめる作業','できるだけ多くのシナジーを見込み、高い値段を正当化する作業','相手の正味の財産の額を、そのまま買収価格とする作業','A',0),
('a3d30900-0000-4000-8000-000000000000','本文における「のれん」の説明として正しいのは、どれか。','払う額から相手の正味の財産を引いた、財産を超えて払う部分','二つの会社が一つになって生まれる、追加の価値','買収後に統合にかかる、システムや人の再配置のコスト','相手が単独で今後生み出す稼ぎを、今の価値に直した額','A',1),
('a3d30900-0000-4000-8000-000000000000','本文が挙げる「失敗①:シナジーを明るく見積もりすぎる」への修正は、どれか。','見込んだシナジーをそのまま使い、統合コストは考えない','シナジーは半分に割り引いて使い、統合のコストを忘れずに引く','相手の言い値を出発点に、それに見合うシナジーを後から探す','すでにかけた時間と費用も判断に含めて、上限を引き上げる','B',2),
('a3d40900-0000-4000-8000-000000000000','本文が示す管理会計の本質は、どれか。','判断のために、数字を作り直すこと','法律で決まった形に従って、外に報告する数字を作ること','会社全体の利益を、ルール通りに一つにまとめること','決算書の数字を、絶対の正解としてそのまま使うこと','A',0),
('a3d40900-0000-4000-8000-000000000000','本文における「限界利益」の定義として正しいのは、どれか。','売上から変動費だけを引いたもの(固定費は引かない)','売上から変動費と固定費の両方を引いたもの','事業の限界利益から、その事業だけの固定費を引いたもの','売上から固定費だけを引いたもの','A',1),
('a3d40900-0000-4000-8000-000000000000','本文が挙げる「失敗③:サンクコストに引きずられる」への修正は、どれか。','これまでいくら投じたかを重視し、無駄にしないため続ける','すでに投じた戻らないお金は判断に入れず、これから変わるお金だけを天秤に乗せる','本社の固定費を各事業に無理やり割り振って、赤字事業を裁く','決算書の原価をそのまま使い、原価割れの注文はすべて断る','B',2);
